<template>
	<view>
		<view class="list-box" v-if="list.length">
			<view class="list-item" v-for="item,index in list" :key="index" @click="handelItemClick(item)">
				<view class="top">
					<view class="code" @click="paste(item.ordersn)"><text>{{item.ordersn}}</text><u-icon
							name="zhuanfa"></u-icon></view>
					<view class="status">
						<view class="status-item bg-yellow" v-if="item.status == 2">{{item.order_status_text}}</view>
						<view class="status-item bg-green" v-else-if="item.status == 3">{{item.order_status_text}}</view>
						<view class="status-item bg-red" v-else-if="item.status == 4">{{item.order_status_text}}</view>
					</view>
				</view>
				<view class="bottom">
					<view class="left">
						<view class="name line2">
							{{item.goods_name}}
						</view>
						<view class="info">
							<text>创建时间：{{item.create_time}}</text>
						</view>						
					</view>
					<view class="right">
						<view class="codeqr">
							
						</view>
					</view>
				</view>
			</view>
		</view>		
		<template v-else>
			<view class="empty-data">
				<u-empty text="数据为空" mode="data"></u-empty>
			</view>
		</template>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			list: {
				type: Array,
				default: () => []
			},
		},
		data() {
			return {
				
			};
		},
		computed: {

		},
		watch: {
			
		},
		created() {

		},
		mounted() {

		},
		methods: {
			// 复制
			paste(val) {
				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			// 时间戳转日期
			parseTime(timestamp) {
				return this.$u.timeFormat(timestamp, 'yyyy-mm-dd hh:MM:ss')
			},
			// item点击
			handelItemClick(row) {
				// this.$emit('show-card', row)
			},		
		},
	};
</script>

<style scoped lang="scss" scoped>	

	.list-box {
		display: flex;
		flex-direction: column;
		gap: 10rpx;
		.list-item {
			position: relative;
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;

			.top {
				display: flex;
				align-items: center;

				.code {
					flex: 1;

					&>text {
						margin-right: 10rpx;
					}
				}

				.status {
					.status-item {
						border-radius: 30rpx;
						padding: 2rpx 20rpx;
						color: #fff;
						font-size: 26rpx;
					}					
				}
			}

			.bottom {
				display: flex;

				.left {
					flex: 1;
					display: flex;
					flex-direction: column;
					justify-content: space-between;

					.name{
						font-size: 26rpx;
					}
					.info {
						display: flex;
						flex-direction: column;
						gap: 5rpx;
						margin-bottom: 10rpx;
						font-size: 26rpx;

						text {
							color: #909399;
						}
					}
					
				}

				.right {}
			}
		}
	}
</style>