<template>
	<view class="">
		<u-navbar title="兑换卡密日志" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item check-btn" @click="handelFilterClick">
						<u-icon name="search"></u-icon>
						<text>筛选</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}" @scrolltolower="lower">
			<card-log-list :list="list" />
			<u-loadmore :status="loading" icon-type="circle" @loadmore="lower" v-show="list.length" />
		</scroll-view>
		<card-log-filter ref="card-log-filter" @ok="handelFilterChange" />
	</view>
</template>

<script>
	import CardLogList from './components/card-log-list'
	import CardLogFilter from './components/card-log-filter'
	export default {
		components: {
			'card-log-list': CardLogList,
			'card-log-filter': CardLogFilter,
		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					page: 1,
					limit: 20,
					keyword: '',
					keyword_type: '',
					create_time: '',
					card_id: '', //卡密ID
				},

				list: [], //列表
				total: 0,
				loading: 'loadmore',
			};
		},
		onReady() {
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad(e) {
			const {
				id
			} = e
			if (!id) {
				this.$util.msg('卡密id不能为空')
				setTimeout(() => {
					this.$util.back()
				}, 500)
				return
			}
			this.queryForm.card_id = id
			this.fetchData()
		},
		onHide() {
			this.queryForm = this.$options.data().queryForm
		},
		methods: {
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
				} = await this.$u.api.goodsCardLogList(this.queryForm)
				this.total = total
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},

			// 筛选点击
			handelFilterClick() {
				this.$refs['card-log-filter'].showEdit(this.queryForm)
			},
			// 筛选回调
			handelFilterChange(e) {
				this.queryForm = Object.assign({}, e)
				this.reloadData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {
			white-space: nowrap;
		}

		.btn-item:active {
			opacity: .6;
		}

		.check-btn {
			padding: 4rpx 20rpx;
			background: linear-gradient(-90deg, #ff5c2d, #ff5c2d);
			border-radius: 44rpx;
			color: #fff;
		}
	}
</style>