<template>
	<u-mask :show="show" @click="show = false" :z-index="979">
		<view class="warp" @click.stop>
			<u-sticky>
				<!-- 只能有一个根元素 -->
				<view class="sticky">
					<u-form :model="queryForm" ref="uForm" :label-width="140">
						<u-form-item label="搜索类型">
							<u-input :value="keywordTypeText" type="select" @click="showKeywordType = true" />
							<u-action-sheet :list="keywordTypeList" v-model="showKeywordType"
								@click="handelKeywordTypeChange"></u-action-sheet>
						</u-form-item>
						<u-form-item label="关键字"><u-input v-model="queryForm.keyword" /></u-form-item>
						<u-form-item label="创建时间">
							<uni-datetime-picker v-model="queryForm.create_time" type="datetimerange" />
						</u-form-item>
						<u-form-item label="" :border-bottom="false">
							<u-button class="fail" @click="show=false">取消</u-button>
							<u-button @click="submit">提交</u-button>
						</u-form-item>
					</u-form>
				</view>
			</u-sticky>
		</view>
	</u-mask>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			return {
				show: false,
				queryForm: {
					page: 1,
					limit: 20,
					keyword: '',
					keyword_type: '',
					create_time: '',
					expire_time: '',
					status:'',//1=未使用,2=已使用,3=已冻结,4=已过期
					batch_id:'',//卡组ID
					batch_log_id:'',//卡组生成日志ID
				},

				keywordTypeList: [{
						text: '卡密',
						value: 1,
					},
					{
						text: '卡组名称',
						value: 2,
					},					
					{
						text: '清空',
						color: '#fa3534'
					}
				],
				showKeywordType: false,	
				
			};
		},
		computed: {
			keywordTypeText: {
				get() {
					if (this.queryForm.keyword_type != '') {
						let find = this.keywordTypeList.find(item => item.value == this.queryForm.keyword_type)
						return find.text
					} else {
						return ''
					}
				}
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			showEdit(queryForm) {
				this.queryForm = Object.assign({}, {
					...queryForm
				})
				this.show = true
			},
			handelKeywordTypeChange(e) {
				if (this.keywordTypeList[e].value)
					this.queryForm.keyword_type = this.keywordTypeList[e].value
				else
					this.queryForm.keyword_type = ''
			},
			// 提交
			submit(){				
				this.$emit('ok',this.queryForm)
				this.show = false
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.warp {}

	.sticky {
		padding: 20rpx;
		background-color: #fff;
	}

	::v-deep {
		.u-drawer-content-visible{
			border-radius:30rpx 30rpx 0 0;
		}
		.u-sticky {
			left: 0 !important;
			width: 100% !important;
		}

		.u-sticky-wrap {
			height: auto !important;
		}
		.uni-input-wrapper{
			font-size: 26rpx;
		}
		.uni-textarea-compute{
			font-size: 26rpx;
		}
		
		.u-form-item{
			font-size: 26rpx;
		}
		.uni-date-x{
			border-radius: 56rpx;
			.icon-calendar{
				padding-left: 24rpx;
			}
		}
		.uni-date-x--border{
			border-radius: 56rpx;
		}
		.uni-date__x-input{
			line-height: 60rpx;
			height: 60rpx;
		}
		.uni-input-input{
				font-size: 26rpx;
		}
		.u-size-default{
			font-size: 26rpx;
			height: 60rpx;
			line-height: 58rpx;
			padding: 0 80rpx;
			margin-top: 26rpx;
			background: linear-gradient(90deg, #FE8A56 0%, #FF504B 100%);
			border-radius: 60rpx;
			color: #fff;
		}
		
		.fail{
			background:linear-gradient(90deg, #353535 0%, #909399 100%);
		}
		.u-hairline-border::after{
			border-radius: 60rpx;
		}
	}
</style>